  ```javascript
  if (!result.valid) {
    setAttr(field, 'aria-invalid', 'true');          // ← add
    srUtils.markInvalid(field, errorEl);
    …
  } else {
    removeAttr(field, 'aria-invalid');              // ← add
    srUtils.markValid(field, errorEl);
  }
  ```

